const { ethers } = require("ethers");

// ABI fragments for ERC20 and DEX interactions
const ERC20_ABI = [
  "function name() view returns (string)",
  "function symbol() view returns (string)",
  "function decimals() view returns (uint8)",
  "function balanceOf(address owner) view returns (uint256)",
  "function allowance(address owner, address spender) view returns (uint256)",
  "function approve(address spender, uint256 amount) returns (bool)",
  "function transfer(address to, uint256 amount) returns (bool)",
  "event Approval(address indexed owner, address indexed spender, uint256 value)",
  "event Transfer(address indexed from, address indexed to, uint256 value)"
];

const DEX_ABI = [
  "function swapExactTokensForTokens(uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to, uint256 deadline) returns (uint256[] memory amounts)",
  "function getAmountsOut(uint256 amountIn, address[] calldata path) view returns (uint256[] memory amounts)",
  "function factory() view returns (address)",
  "function WETH() view returns (address)"
];

// Security: Define a reasonable approval multiplier instead of max uint256
// Approving max uint256 is dangerous because:
// 1. If the DEX contract is compromised, attacker can drain ALL your tokens
// 2. If the contract has a bug, unlimited tokens can be moved
// 3. Users lose granular control over their token exposure
const APPROVAL_SAFETY_MULTIPLIER = 2; // Approve only 2x the swap amount
const DEFAULT_SLIPPAGE_BPS = 50; // 0.5% slippage
const DEFAULT_DEADLINE_MINUTES = 20;

class TokenSwapDApp {
  constructor(providerUrl, dexRouterAddress) {
    this.provider = new ethers.JsonRpcProvider(providerUrl);
    this.dexRouterAddress = dexRouterAddress;
    this.signer = null;
    this.dexRouter = null;
    this.approvalCache = new Map(); // Cache allowances to reduce RPC calls
  }

  /**
   * Connect a wallet (via private key for backend or browser wallet for frontend)
   */
  async connectWallet(privateKey) {
    if (privateKey) {
      this.signer = new ethers.Wallet(privateKey, this.provider);
    } else {
      // For browser-based usage with MetaMask etc.
      const browserProvider = new ethers.BrowserProvider(window.ethereum);
      await browserProvider.send("eth_requestAccounts", []);
      this.signer = await browserProvider.getSigner();
    }

    this.dexRouter = new ethers.Contract(
      this.dexRouterAddress,
      DEX_ABI,
      this.signer
    );

    const address = await this.signer.getAddress();
    console.log(`Wallet connected: ${address}`);
    return address;
  }

  /**
   * Get token information
   */
  async getTokenInfo(tokenAddress) {
    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);
    const [name, symbol, decimals] = await Promise.all([
      token.name(),
      token.symbol(),
      token.decimals()
    ]);
    return { address: tokenAddress, name, symbol, decimals };
  }

  /**
   * Get token balance for a given address
   */
  async getTokenBalance(tokenAddress, walletAddress) {
    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);
    const balance = await token.balanceOf(walletAddress);
    const decimals = await token.decimals();
    return {
      raw: balance,
      formatted: ethers.formatUnits(balance, decimals)
    };
  }

  /**
   * Check current allowance for the DEX router
   */
  async checkAllowance(tokenAddress, ownerAddress) {
    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.provider);
    const allowance = await token.allowance(ownerAddress, this.dexRouterAddress);
    return allowance;
  }

  /**
   * SECURITY-FOCUSED APPROVAL: Approve only the necessary amount (with a small buffer)
   * 
   * Why we DON'T approve max uint256:
   * - Unlimited approvals mean a compromised or malicious contract can drain all tokens
   * - This is a common DeFi attack vector (approval phishing/abuse)
   * - Users should maintain minimal necessary approvals
   * 
   * @param {string} tokenAddress - The ERC20 token to approve
   * @param {BigInt} requiredAmount - The exact amount needed for the swap
   * @param {Object} options - Additional options
   * @param {number} options.multiplier - Safety multiplier (default: 2x the required amount)
   * @param {boolean} options.exactAmount - If true, approve exactly the required amount (most secure)
   */
  async approveToken(tokenAddress, requiredAmount, options = {}) {
    if (!this.signer) {
      throw new Error("Wallet not connected. Call connectWallet() first.");
    }

    const {
      multiplier = APPROVAL_SAFETY_MULTIPLIER,
      exactAmount = false
    } = options;

    const ownerAddress = await this.signer.getAddress();
    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);
    const tokenInfo = await this.getTokenInfo(tokenAddress);

    // Check existing allowance first
    const currentAllowance = await this.checkAllowance(tokenAddress, ownerAddress);

    console.log(
      `Current allowance for ${tokenInfo.symbol}: ${ethers.formatUnits(currentAllowance, tokenInfo.decimals)}`
    );

    // If current allowance is sufficient, no need to approve again
    if (currentAllowance >= requiredAmount) {
      console.log("Sufficient allowance already exists. No approval needed.");
      return { alreadyApproved: true, allowance: currentAllowance };
    }

    // SECURITY: Calculate a safe approval amount
    // Option 1 (most secure): Approve exactly the required amount
    // Option 2 (balanced): Approve a small multiple to reduce future approval transactions
    let approvalAmount;

    if (exactAmount) {
      // Most secure: approve only what's needed
      approvalAmount = requiredAmount;
      console.log(
        `[SECURE] Approving exact amount: ${ethers.formatUnits(approvalAmount, tokenInfo.decimals)} ${tokenInfo.symbol}`
      );
    } else {
      // Balanced approach: approve a reasonable multiple
      approvalAmount = requiredAmount * BigInt(multiplier);

      // SECURITY: Cap the approval to the user's current balance as an additional safeguard
      const balance = await token.balanceOf(ownerAddress);
      if (approvalAmount > balance) {
        approvalAmount = balance;
        console.log(
          `[SECURE] Approval capped to current balance: ${ethers.formatUnits(approvalAmount, tokenInfo.decimals)} ${tokenInfo.symbol}`
        );
      } else {
        console.log(
          `[SECURE] Approving ${multiplier}x amount: ${ethers.formatUnits(approvalAmount, tokenInfo.decimals)} ${tokenInfo.symbol}`
        );
      }
    }

    // SECURITY WARNING: Explicitly reject max uint256 approvals
    const MAX_UINT256 = ethers.MaxUint256;
    if (approvalAmount === MAX_UINT256) {
      throw new Error(
        "SECURITY: Unlimited (max uint256) approvals are not allowed. " +
        "This protects users from approval abuse attacks where a compromised " +
        "contract could drain all approved tokens."
      );
    }

    // If there's an existing non-zero allowance, reset to 0 first (required by some tokens like USDT)
    if (currentAllowance > 0n) {
      console.log("Resetting existing allowance to 0 (required by some tokens)...");
      const resetTx = await token.approve(this.dexRouterAddress, 0n);
      await resetTx.wait();
      console.log("Allowance reset to 0.");
    }

    // Submit the approval transaction
    const tx = await token.approve(this.dexRouterAddress, approvalAmount);
    console.log(`Approval transaction submitted: ${tx.hash}`);

    const receipt = await tx.wait();
    console.log(`Approval confirmed in block ${receipt.blockNumber}`);

    // Update cache
    this.approvalCache.set(
      `${tokenAddress}-${ownerAddress}`,
      { amount: approvalAmount, timestamp: Date.now() }
    );

    return {
      alreadyApproved: false,
      approvalAmount,
      transactionHash: tx.hash,
      blockNumber: receipt.blockNumber
    };
  }

  /**
   * Revoke approval for a token (set allowance to 0)
   * Good security practice: revoke approvals when no longer needed
   */
  async revokeApproval(tokenAddress) {
    if (!this.signer) {
      throw new Error("Wallet not connected. Call connectWallet() first.");
    }

    const token = new ethers.Contract(tokenAddress, ERC20_ABI, this.signer);
    const tokenInfo = await this.getTokenInfo(tokenAddress);

    console.log(`Revoking approval for ${tokenInfo.symbol}...`);
    const tx = await token.approve(this.dexRouterAddress, 0n);
    const receipt = await tx.wait();

    console.log(`Approval revoked for ${tokenInfo.symbol}. Tx: ${tx.hash}`);

    // Clear cache
    const ownerAddress = await this.signer.getAddress();
    this.approvalCache.delete(`${tokenAddress}-${ownerAddress}`);

    return {
      transactionHash: tx.hash,
      blockNumber: receipt.blockNumber
    };
  }

  /**
   * Get a quote for a token swap
   */
  async getSwapQuote(tokenInAddress, tokenOutAddress, amountIn) {
    if (!this.dexRouter) {
      throw new Error("DEX router not initialized. Call connectWallet() first.");
    }

    const tokenIn = await this.getTokenInfo(tokenInAddress);
    const tokenOut = await this.getTokenInfo(tokenOutAddress);

    const amountInWei = ethers.parseUnits(amountIn.toString(), tokenIn.decimals);
    const path = [tokenInAddress, tokenOutAddress];

    try {
      const amounts = await this.dexRouter.getAmountsOut(amountInWei, path);
      const amountOut = amounts[amounts.length - 1];

      return {
        tokenIn: tokenIn.symbol,
        tokenOut: tokenOut.symbol,
        amountIn: amountIn.toString(),
        amountInWei: amountInWei,
        amountOut: ethers.formatUnits(amountOut, tokenOut.decimals),
        amountOutWei: amountOut,
        path,
        priceImpact: this._estimatePriceImpact(amountInWei, amountOut, tokenIn.decimals, tokenOut.decimals)
      };
    } catch (error) {
      throw new Error(`Failed to get swap quote: ${error.message}`);
    }
  }

  /**
   * Execute a token swap with safety checks
   */
  async executeSwap(tokenInAddress, tokenOutAddress, amountIn, options = {}) {
    if (!this.signer || !this.dexRouter) {
      throw new Error("Wallet not connected. Call connectWallet() first.");
    }

    const {
      slippageBps = DEFAULT_SLIPPAGE_BPS,
      deadlineMinutes = DEFAULT_DEADLINE_MINUTES,
      approvalMultiplier = APPROVAL_SAFETY_MULTIPLIER,
      exactApproval = false,
      autoRevokeAfterSwap = false
    } = options;

    const ownerAddress = await this.signer.getAddress();
    const tokenIn = await this.getTokenInfo(tokenInAddress);
    const tokenOut = await this.getTokenInfo(tokenOutAddress);

    const amountInWei = ethers.parseUnits(amountIn.toString(), tokenIn.decimals);

    // Step 1: Verify sufficient balance
    const balance = await this.getTokenBalance(tokenInAddress, ownerAddress);
    if (balance.raw < amountInWei) {
      throw new Error(
        `Insufficient ${tokenIn.symbol} balance. ` +
        `Have: ${balance.formatted}, Need: ${amountIn}`
      );
    }

    // Step 2: Get quote
    console.log(`\nGetting swap quote for ${amountIn} ${tokenIn.symbol} -> ${tokenOut.symbol}...`);
    const quote = await this.getSwapQuote(tokenInAddress, tokenOutAddress, amountIn);
    console.log(`Expected output: ${quote.amountOut} ${tokenOut.symbol}`);

    // Step 3: Calculate minimum output with slippage protection
    const slippageMultiplier = 10000n - BigInt(slippageBps);
    const amountOutMin = (quote.amountOutWei * slippageMultiplier) / 10000n;
    console.log(
      `Minimum output (${slippageBps / 100}% slippage): ${ethers.formatUnits(amountOutMin, tokenOut.decimals)} ${tokenOut.symbol}`
    );

    // Step 4: Handle approval (SECURE - not max uint256)
    console.log("\nHandling token approval...");
    const approvalResult = await this.approveToken(tokenInAddress, amountInWei, {
      multiplier: approvalMultiplier,
      exactAmount: exactApproval
    });

    if (approvalResult.alreadyApproved) {
      console.log("Using existing approval.");
    } else {
      console.log(`New approval granted. Tx: ${approvalResult.transactionHash}`);
    }

    // Step 5: Execute the swap
    const deadline = Math.floor(Date.now() / 1000) + deadlineMinutes * 60;
    const path = [tokenInAddress, tokenOutAddress];

    console.log("\nExecuting swap...");
    try {
      const tx = await this.dexRouter.swapExactTokensForTokens(
        amountInWei,
        amountOutMin,
        path,
        ownerAddress,
        deadline
      );

      console.log(`Swap transaction submitted: ${tx.hash}`);
      const receipt = await tx.wait();
      console.log(`Swap confirmed in block ${receipt.blockNumber}`);

      // Step 6: Optionally revoke approval after swap for maximum security
      if (autoRevokeAfterSwap) {
        console.log("\nAuto-revoking approval for security...");
        await this.revokeApproval(tokenInAddress);
      }

      // Step 7: Get final balances
      const finalBalanceIn = await this.getTokenBalance(tokenInAddress, ownerAddress);
      const finalBalanceOut = await this.getTokenBalance(tokenOutAddress, ownerAddress);

      return {
        success: true,
        transactionHash: tx.hash,
        blockNumber: receipt.blockNumber,
        amountIn: `${amountIn} ${tokenIn.symbol}`,
        expectedAmountOut: `${quote.amountOut} ${tokenOut.symbol}`,
        minimumAmountOut: `${ethers.formatUnits(amountOutMin, tokenOut.decimals)} ${tokenOut.symbol}`,
        finalBalances: {
          [tokenIn.symbol]: finalBalanceIn.formatted,
          [tokenOut.symbol]: finalBalanceOut.formatted
        },
        approvalRevoked: autoRevokeAfterSwap
      };
    } catch (error) {
      throw new Error(`Swap execution failed: ${error.message}`);
    }
  }

  /**
   * Audit all active approvals for a list of tokens
   * Helps users identify and revoke unnecessary approvals
   */
  async auditApprovals(tokenAddresses) {
    if (!this.signer) {
      throw new Error("Wallet not connected. Call connectWallet() first.");
    }

    const ownerAddress = await this.signer.getAddress();
    const approvals = [];

    for (const tokenAddress of tokenAddresses) {
      try {
        const tokenInfo = await this.getTokenInfo(tokenAddress);
        const allowance = await this.checkAllowance(tokenAddress, ownerAddress);
        const balance = await this.getTokenBalance(tokenAddress, ownerAddress);

        const isUnlimited = allowance >= ethers.MaxUint256 / 2n;

        approvals.push({
          token: tokenInfo.symbol,
          address: tokenAddress,
          allowance: ethers.formatUnits(allowance, tokenInfo.decimals),
          allowanceRaw: allowance,
          balance: balance.formatted,
          isUnlimited,
          riskLevel: isUnlimited ? "HIGH" : allowance > balance.raw ? "MEDIUM" : "LOW",
          recommendation: isUnlimited
            ? "REVOKE IMMEDIATELY - Unlimited approval detected"
            : allowance > 0n && allowance > balance.raw * 10n
              ? "Consider revoking - Approval significantly exceeds balance"
              : allowance > 0n
                ? "Monitor - Approval within reasonable range"
                : "Safe - No active approval"
        });
      } catch (error) {
        approvals.push({
          token: "Unknown",
          address: tokenAddress,
          error: error.message
        });
      }
    }

    return approvals;
  }

  /**
   * Batch revoke approvals for multiple tokens
   */
  async batchRevokeApprovals(tokenAddresses) {
    const results = [];
    for (const tokenAddress of tokenAddresses) {
      try {
        const result = await this.revokeApproval(tokenAddress);
        results.push({ tokenAddress, success: true, ...result });
      } catch (error) {
        results.push({ tokenAddress, success: false, error: error.message });
      }
    }
    return results;
  }

  /**
   * Estimate price impact (simplified)
   */
  _estimatePriceImpact(amountIn, amountOut, decimalsIn, decimalsOut) {
    // This is a simplified estimation; real price impact requires pool reserve data
    const normalizedIn = parseFloat(ethers.formatUnits(amountIn, decimalsIn));
    const normalizedOut = parseFloat(ethers.formatUnits(amountOut, decimalsOut));
    if (normalizedIn === 0) return "0%";
    const rate = normalizedOut / normalizedIn;
    return `Rate: ${rate.toFixed(6)}`;
  }
}

